import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F09_毛利變動與經營槓桿審計_財務分析專家.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F09_毛利變動與經營槓桿審計_財務分析專家.md"}'),l={name:"審計報告庫/財務審計/6903_巨漢/20260502/F09_毛利變動與經營槓桿審計_財務分析專家.md"};function i(_,a,n,s,p,h){return e(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>毛利率、營益率與淨利率的連動關係為何？是否存在經營槓桿放大或侵蝕損益的現象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢三率呈現結構性下滑：GM 40.6%→27.7%（-12.9pp）、OPM 35.8%→23.7%（-12.1pp）、NPM 28.6%→19.6%（-9pp）。三率降幅同步，主因工程案結構轉向低毛利大型案，非費用失控。經營槓桿係數從 2024 年 1.03 降至 2025 年 0.58，獲利彈性趨弱。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B+（持平偏良）。三率雖下滑，但 2025 年 OPM 23.7% 仍在工程統包業中名列前段（高於同業均值 ~18%）。利空：若毛利率續跌至 25% 以下（同業均水準），競爭優勢將弱化。費用率控制在 4% 以下為亮點。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>三率趨勢</strong>：2023→2025 毛利率從 40.6% 高點逐年下滑至 27.7%，降幅 12.9pp。營益率跟隨毛利率同步下降（35.8%→23.7%），降幅相近（12.1pp），營費率從 4.8% 降至 4.0%，費用控管得宜。淨利率從 28.6% 降至 19.6%，稅率穩定無干擾。</p></li><li><p><strong>經營槓桿分析</strong>：2024 年槓桿係數 1.03（營收成長 1% 帶動營益成長 1.03%），2025 年降至 0.58。主因 2025 年營收成長主要由低毛利大型專案貢獻，營益率提升幅度不如營收增幅。</p></li><li><p><strong>獲利結構診斷</strong>：毛利總額從 2023 年 11.64 億降至 2024 年 8.74 億（因毛利率下跌），2025 年回升至 9.97 億。營收成長但毛利未等比增加，典型的「增量不增利」風險。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>結構性獲利惡化風險</strong>：毛利率連續 3 年下滑，若此趨勢不變，2026 年 GM 可能跌破 25%，屆時 OPM 將降至 20% 以下，獲利能力將從「優異」降級為「平庸」，股價評價將面臨下修壓力。</li><li><strong>案源結構風險</strong>：低毛利大型案佔比提高雖推升營收，但稀釋整體獲利。若公司無法提升高毛利中小型案的比例，獲利結構將持續惡化。需追蹤每季毛利率變化。</li><li><strong>費用率已無下調空間</strong>：營業費用率 4% 已是極低水準，無法再靠縮減費用來維持營益率。唯一的改善途徑是提升毛利率——這取決於案源選擇能力。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>財務分析工具.py：margin_analysis 6903</li></ul>',12)])])}const u=t(l,[["render",i]]);export{c as __pageData,u as default};
